import{_ as e,c as o,o as a,ag as s}from"./chunks/framework.DD2hp6gW.js";const h=JSON.parse('{"title":"Product Assignments","description":"","frontmatter":{},"headers":[],"relativePath":"assignments.md","filePath":"assignments.md","lastUpdated":1777110900000}'),r={name:"assignments.md"};function i(n,t,l,c,g,d){return a(),o("div",null,t[0]||(t[0]=[s('<h1 id="product-assignments" tabindex="-1">Product Assignments <a class="header-anchor" href="#product-assignments" aria-label="Permalink to &quot;Product Assignments&quot;">​</a></h1><p><strong>Assignments</strong> allow you to control exactly where your Option Groups appear on your storefront. OptionBay uses a rule-based system that gives you the flexibility to target your entire catalog, specific categories, individual tags, or hand-picked products.</p><h2 id="accessing-assignments" tabindex="-1">Accessing Assignments <a class="header-anchor" href="#accessing-assignments" aria-label="Permalink to &quot;Accessing Assignments&quot;">​</a></h2><p>Assignment rules are managed within each <strong>Option Group</strong>. When editing a group in the Addon Builder, look for the <strong>Assignments</strong> section located below the field builder area.</p><h2 id="assignment-types" tabindex="-1">Assignment Types <a class="header-anchor" href="#assignment-types" aria-label="Permalink to &quot;Assignment Types&quot;">​</a></h2><p>You can mix and match these rules to get the perfect coverage:</p><h3 id="_1-global-all-products" tabindex="-1">1. Global (All Products) <a class="header-anchor" href="#_1-global-all-products" aria-label="Permalink to &quot;1. Global (All Products)&quot;">​</a></h3><p>If enabled, this group will appear on <strong>every single product</strong> in your WooCommerce store. This is perfect for universal options that apply to everything you sell.</p><p><strong>Best for:</strong> Rush Processing, Gift Wrapping, Insurance, Terms &amp; Conditions.</p><h3 id="_2-specific-products" tabindex="-1">2. Specific Products <a class="header-anchor" href="#_2-specific-products" aria-label="Permalink to &quot;2. Specific Products&quot;">​</a></h3><p>Search for and select individual products by name. The group will only appear on these specific items.</p><p><strong>Best for:</strong> Highly customized products that need unique options (e.g., a single &quot;Custom Engraved Watch&quot; product that needs an engraving text field).</p><h3 id="_3-product-categories" tabindex="-1">3. Product Categories <a class="header-anchor" href="#_3-product-categories" aria-label="Permalink to &quot;3. Product Categories&quot;">​</a></h3><p>Select one or more WooCommerce categories. Any product assigned to these categories will automatically display this option group.</p><p><strong>Best for:</strong> Managing options at scale for entire collections. For example, all products in the &quot;T-Shirts&quot; category automatically get the &quot;Sizing &amp; Color&quot; option group.</p><h3 id="_4-product-tags" tabindex="-1">4. Product Tags <a class="header-anchor" href="#_4-product-tags" aria-label="Permalink to &quot;4. Product Tags&quot;">​</a></h3><p>Similar to categories, you can target products based on their WordPress tags. This is useful when you need cross-category targeting.</p><p><strong>Best for:</strong> Targeting products that share a trait across multiple categories (e.g., all products tagged &quot;Personalizable&quot; regardless of whether they&#39;re in &quot;Mugs&quot; or &quot;T-Shirts&quot;).</p><h2 id="priority-ordering" tabindex="-1">Priority &amp; Ordering <a class="header-anchor" href="#priority-ordering" aria-label="Permalink to &quot;Priority &amp; Ordering&quot;">​</a></h2><p>When a product has multiple option groups assigned to it (e.g., both a &quot;Gift Wrapping&quot; global group and a &quot;T-Shirt Sizing&quot; category group), you can control the order in which they appear on the product page using the <strong>Priority</strong> setting.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>How it works</strong></td><td style="text-align:left;">Groups are sorted numerically by their priority value.</td></tr><tr><td style="text-align:left;"><strong>Lower = First</strong></td><td style="text-align:left;">A group with priority <code>1</code> appears above a group with priority <code>10</code>.</td></tr><tr><td style="text-align:left;"><strong>Default</strong></td><td style="text-align:left;">If no priority is set, groups default to <code>10</code>.</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use priorities like <code>5</code>, <code>10</code>, <code>15</code> instead of <code>1</code>, <code>2</code>, <code>3</code>. This leaves room to insert new groups between existing ones without having to renumber everything.</p></div><h2 id="assignment-exclusions" tabindex="-1">Assignment Exclusions <a class="header-anchor" href="#assignment-exclusions" aria-label="Permalink to &quot;Assignment Exclusions&quot;">​</a></h2><p>Exclusions allow you to create <strong>negative rules</strong> — telling OptionBay where a group should <strong>not</strong> appear. This is incredibly powerful for handling exceptions to broad rules.</p><h3 id="how-exclusions-work" tabindex="-1">How Exclusions Work <a class="header-anchor" href="#how-exclusions-work" aria-label="Permalink to &quot;How Exclusions Work&quot;">​</a></h3><p>If a group is both <strong>included</strong> (e.g., via a &quot;Global&quot; rule) and <strong>excluded</strong> (e.g., via a &quot;Specific Product&quot; exclusion), the <strong>exclusion always wins</strong>. The group will not be displayed on that product.</p><h3 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Scenario</th><th style="text-align:left;">Inclusion</th><th style="text-align:left;">Exclusion</th></tr></thead><tbody><tr><td style="text-align:left;">Gift wrap on everything except digital downloads</td><td style="text-align:left;">Global (All Products)</td><td style="text-align:left;">Category: &quot;Digital Downloads&quot;</td></tr><tr><td style="text-align:left;">Size chart on all apparel except socks</td><td style="text-align:left;">Category: &quot;Apparel&quot;</td><td style="text-align:left;">Category: &quot;Socks&quot;</td></tr><tr><td style="text-align:left;">Custom engraving on all jewelry except earrings</td><td style="text-align:left;">Category: &quot;Jewelry&quot;</td><td style="text-align:left;">Tag: &quot;Earrings&quot;</td></tr></tbody></table><h2 id="troubleshooting-assignments" tabindex="-1">Troubleshooting Assignments <a class="header-anchor" href="#troubleshooting-assignments" aria-label="Permalink to &quot;Troubleshooting Assignments&quot;">​</a></h2><p>If a group isn&#39;t appearing on a product as expected, check the following:</p><ol><li><strong>Status:</strong> Ensure the Option Group is set to <strong>Published</strong>, not Draft. Draft groups are never shown on the frontend.</li><li><strong>Exclusions:</strong> Check if there is an active Exclusion rule targeting that specific product, category, or tag. Remember: <strong>Exclusions always override inclusions.</strong></li><li><strong>Cache:</strong> If you are using a caching plugin (like WP Rocket, W3 Total Cache, or LiteSpeed Cache), you may need to clear your cache after changing assignment rules.</li><li><strong>Theme Hooks:</strong> Your theme must fire the standard <code>woocommerce_before_add_to_cart_button</code> hook. Most themes do, but some custom page builders might require manual placement.</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./conditional-logic.html">Learn about Conditional Logic</a></li><li><a href="./settings.html">Managing Global Settings</a></li></ul>',33)]))}const p=e(r,[["render",i]]);export{h as __pageData,p as default};
